{
 "level": "B2–C1",
 "intro": "In this topic, you will learn <strong>passive infinitive and gerund</strong>, key constructions for academic and formal writing.",
 "rules": [
 {
 "label": "Infinitive",
 "color": "emerald",
 "text": "<strong>to be done</strong> - present/future:",
 "example": "The report needs to be finished."
 },
 {
 "label": "Perf. infinitive",
 "color": "blue",
 "text": "<strong>to have been done</strong> is a previous action:",
 "example": "He seems to have been promoted."
 },
 {
 "label": "Gerund",
 "color": "rose",
 "text": "<strong>being done</strong> — process:",
 "example": "She hates being interrupted."
 },
 {
 "label": "Perf. gerund",
 "color": "amber",
 "text": "<strong>having been done</strong> is a previous action:",
 "example": "Having been warned, he was careful."
 }
 ]
}

{
 "title": "1. Four passive forms",
 "intro": "Comparison of active and passive forms of the infinitive and gerund:",
 "items": [
 {
 "label": "Active Inf.",
 "title": "to do",
 "subtitle": "→ Passive: to be done"
 },
 {
 "label": "Perf. Active Inf.",
 "title": "to have done",
 "subtitle": "→ Passive: to have been done"
 },
 {
 "label": "Active Gerund",
 "title": "doing",
 "subtitle": "→ Passive: being done"
 },
 {
 "label": "Perf. Active Ger.",
 "title": "having done",
 "subtitle": "→ Passive: having been done"
 }
 ]
}

{
 "title": "2. Passive infinitive (to be done)",
 "sections": [
 {
 "label": "After need/want/expect",
 "color": "emerald",
 "description": "When someone wants/expects <strong>something to be done</strong>:",
 "examples": [
 {
 "en": "The report needs to be finished by Friday.",
 "ua": "The report needs to be finished by Friday."
 },
 {
 "en": "I want this issue to be resolved.",
 "ua": "I want this issue to be resolved."
 },
 {
 "en": "They expect the project to be approved.",
 "ua": "They expect the project to be approved."
 }
 ]
 },
 {
 "label": "After seem/appear",
 "color": "blue",
 "description": "For impression, guesswork:",
 "examples": [
 {
 "en": "The door seems to be locked.",
 "ua": "The door seems to be locked."
 },
 {
 "en": "He appears to be respected by everyone.",
 "ua": "He appears to be respected by everyone."
 }
 ]
 }
 ]
}

{
 "title": "3. Perfect passive infinitive (to have been done)",
 "sections": [
 {
 "label": "Previous action",
 "color": "emerald",
 "description": "Indicates an action that <strong>happened before</strong>:",
 "examples": [
 {
 "en": "He seems to have been promoted.",
 "ua": "He seems to have been promoted."
 },
 {
 "en": "The documents appear to have been lost.",
 "ua": "The documents appear to have been lost."
 }
 ]
 },
 {
 "label": "Reporting structures",
 "color": "blue",
 "description": "In impersonal constructions with <strong>is said/believed/reported</strong>:",
 "examples": [
 {
 "en": "He is believed to have been kidnapped.",
 "ua": "He is believed to have been kidnapped."
 },
 {
 "en": "She is reported to have been seen in Paris.",
 "ua": "She is reported to have been seen in Paris."
 }
 ]
 }
 ]
}

{
 "title": "4. Passive gerund (being done)",
 "sections": [
 {
 "label": "After verbs of feelings",
 "color": "emerald",
 "description": "After <strong>like, hate, enjoy, avoid</strong>:",
 "examples": [
 {
 "en": "She hates being interrupted.",
 "ua": "She hates being interrupted."
 },
 {
 "en": "Nobody likes being criticized.",
 "ua": "Nobody likes being criticized."
 },
 {
 "en": "He enjoys being praised.",
 "ua": "He enjoys being praised."
 }
 ]
 },
 {
 "label": "After prepositions",
 "color": "blue",
 "description": "After <strong>without, after, before, despite</strong>:",
 "examples": [
 {
 "en": "He left without being noticed.",
 "ua": "He left without being noticed."
 },
 {
 "en": "After being rejected, she tried again.",
 "ua": "After being rejected, she tried again."
 },
 {
 "en": "Despite being warned, he continued.",
 "ua": "Despite being warned, he continued."
 }
 ]
 }
 ]
}

{
 "title": "5. Perfect passive gerund (having been done)",
 "sections": [
 {
 "label": "Cause → effect",
 "color": "emerald",
 "description": "For actions that <strong>preceded others</strong>:",
 "examples": [
 {
 "en": "Having been warned, he was more careful.",
 "ua": "Having been warned, he was more careful."
 },
 {
 "en": "Having been told the truth, she felt relieved.",
 "ua": "Having been told the truth, she felt relieved."
 }
 ]
 },
 {
 "label": "Formal style",
 "color": "blue",
 "description": "Often in <strong>academic and official</strong> writing:",
 "examples": [
 {
 "en": "Having been approved, the project will begin.",
 "ua": "Having been approved, the project will begin."
 },
 {
 "en": "Having been elected, she took office.",
 "ua": "Having been elected, she took office."
 }
 ]
 }
 ]
}

{
 "title": "6. Summary table of forms",
 "intro": "All passive forms of the infinitive and gerund:",
 "rows": [
 {
 "en": "to be + V3",
 "ua": "to be + V3",
 "note": "The work needs to be done."
 },
 {
 "en": "to have been + V3",
 "ua": "to have been + V3",
 "note": "He seems to have been promoted."
 },
 {
 "en": "being + V3",
 "ua": "being + V3",
 "note": "She hates being interrupted."
 },
 {
 "en": "having been + V3",
 "ua": "having been + V3",
 "note": "Having been warned, he left."
 }
 ],
 "warning": "📌 Perfect forms indicate an action that preceded another!"
}
